51	public:
52	  CPU cpu;
53	  PLATFORM platform;
54	
55	  // AXI bridges (only used when is_axi == true, null otherwise)
56	  std::unique_ptr<axi_to_tlm_bridge<bus_width>> mem_bridge;
57	  std::unique_ptr<axi_to_tlm_bridge<bus_width>> mmio_bridge;
58	  std::unique_ptr<tlm_to_axi_bridge<bus_width>> hvm_bridge;
59	  std::unique_ptr<tlm_to_axi_bridge<bus_width>> slv_bridge;
60	
61	  // sys bus (64-bit slave port on CPU, needs width adapter to 256-bit
62	  // interconnect)
63	  static constexpr std::size_t sys_bus_width = 64;
64	  std::unique_ptr<socket_width_adapter<bus_width, sys_bus_width>> sys_adapter;
65	  std::unique_ptr<tlm_to_axi_bridge<sys_bus_width>> sys_bridge;
66	
67	#if _NDS_IOCP_NUM > 0
68	  // iocp_master connects directly to CPU, not through the interconnect.
69	  // It needs to speak the CPU's bus protocol.
70	  using IocpInitiatorType = std::
71	    conditional_t<is_axi, AxiPeInitiator<bus_width>, AhbPeInitiator<bus_width>>;
72	  IocpInitiatorType iocp_master;
73	#endif // _NDS_IOCP_NUM
