86	  Simulator(const sc_core::sc_module_name& name)
87	      : sc_core::sc_module{name}, dtm(platform.dtm)
88	  {
89	    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
90	             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);
91	
92	    // --- CPU memory BFM → interconnect ---
93	    if constexpr (is_axi) {
94	      mem_bridge = make_axi_to_tlm("mem_bridge", cpu.mem_bfm.isckt);
95	      platform.interconnect.bind_initiator(mem_bridge->tlm_isck);
96	    } else {
97	      platform.interconnect.bind_initiator(cpu.mem_bfm.isckt);
98	    }
99	
100	    // --- CPU MMIO BFM → interconnect ---
101	    if constexpr (requires { cpu.mmio_bfm; }) {
102	      if constexpr (is_axi) {
103	        mmio_bridge = make_axi_to_tlm("mmio_bridge", cpu.mmio_bfm.isckt);
104	        platform.interconnect.bind_initiator(mmio_bridge->tlm_isck);
105	      } else {
106	        platform.interconnect.bind_initiator(cpu.mmio_bfm.isckt);
107	      }
108	    }
109	
110	    // --- CPU HVM subordinate port ---
111	    if constexpr (requires { cpu.hvm_bfm; }) {
112	      if constexpr (is_axi) {
113	        hvm_bridge = make_tlm_to_axi("hvm_bridge", cpu.hvm_bfm.tsckt);
114	        platform.interconnect.bind_target(
115	          hvm_bridge->tlm_tsck,
116	          {CPU::NDS_HVM_BASE,
117	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
118	      } else {
119	        platform.interconnect.bind_target(
120	          cpu.hvm_bfm.tsckt,
121	          {CPU::NDS_HVM_BASE,
122	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
123	      }
124	      platform.custom_master.hvm_base = CPU::NDS_HVM_BASE;
125	    }
126	
127	    // --- CPU slave port ---
128	    if constexpr (requires { cpu.slv_bfm; }) {
129	      if constexpr (is_axi) {
130	        slv_bridge = make_tlm_to_axi("slv_bridge", cpu.slv_bfm.tsckt);
131	        platform.interconnect.bind_target(slv_bridge->tlm_tsck,
132	                                          {HART0_ILM_BASE, HART0_DLM_END});
133	      } else {
134	        platform.interconnect.bind_target(cpu.slv_bfm.tsckt,
135	                                          {HART0_ILM_BASE, HART0_DLM_END});
136	      }
137	      platform.custom_master.ilm_base = HART0_ILM_BASE;
138	      platform.custom_master.dlm_base = HART0_DLM_BASE;
139	    }
140	
141	    // --- CPU sys bus (slave port, 64-bit) → interconnect ---
142	    if constexpr (requires { cpu.sys_bfm; }) {
143	      sys_adapter =
144	        std::make_unique<socket_width_adapter<bus_width, sys_bus_width>>(
145	          "sys_adapter");
146	      sys_bridge =
147	        std::make_unique<tlm_to_axi_bridge<sys_bus_width>>("sys_bridge");
148	      sys_bridge->pe.clk_i.bind(platform.clk);
149	      sys_bridge->axi_isck.bind(cpu.sys_bfm.tsckt);
150	      sys_adapter->isck.bind(sys_bridge->tlm_tsck);
151	      platform.interconnect.bind_target(sys_adapter->tsck,
152	                                        {MLIF_BASE, SLIF_END});
153	    }
154	
155	#if _NDS_IOCP_NUM > 0
156	    iocp_master.protocol_engine.clk_i.bind(platform.clk);
157	    iocp_master.socket.bind(cpu.iocp_bfm.tsckt);
158	#endif // _NDS_IOCP_NUM
159	  }
