205	  void load_image(const std::string& path, MEM_TYPE type)
206	  {
207	    switch (type) {
208	    case MEM_TYPE::ILM:
209	      if constexpr (requires { cpu.set_ilm({}); }) {
210	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
211	      } else {
212	        throw std::runtime_error(
213	          "CPU does not support ILM - cannot load ILM ROM image");
214	      }
215	      break;
216	
217	    case MEM_TYPE::DLM:
218	      if constexpr (requires { cpu.set_dlm({}); }) {
219	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
220	      } else {
221	        throw std::runtime_error(
222	          "CPU does not support DLM - cannot load DLM ROM image");
223	      }
224	      break;
225	
226	    case MEM_TYPE::RAM:
227	      read_binary_file(path, [this](const auto& data) {
228	        if (data.size() > platform.main_memory.data.size())
229	          throw std::runtime_error("RAM image size exceeds main memory size");
230	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
231	      });
232	      break;
233	
234	    default:
235	      throw std::runtime_error("Unknown memory type");
236	    }
237	  }
