12	template<std::size_t BusWidth>
13	class SimpleMemory : public sc_core::sc_module
14	{
15	public:
16	  static constexpr uint64_t INVALID_ADDRESS = 0xffffffffffffffff;
17	
18	  const MemoryRegion region;
19	  const MemoryRegion alias_region;
20	  std::vector<uint8_t> data;
21	  unsigned latency = 1;
22	  tlm_utils::simple_target_socket<SimpleMemory<BusWidth>, BusWidth> socket{
23	    "tsck"};
24	
25	  SimpleMemory(const sc_core::sc_module_name& name,
26	               const MemoryRegion& region,
27	               const MemoryRegion& alias_region = {INVALID_ADDRESS,
28	                                                   INVALID_ADDRESS})
29	      : sc_core::sc_module{name},
30	        region(region),
31	        alias_region(alias_region),
32	        data(region.end_address - region.base_address)
33	  {
34	    this->socket.register_b_transport(this, &SimpleMemory::b_transport);
35	  }
36	
37	  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& delay)
38	  {
39	    auto cycles = handle_trans(trans);
40	    if (trans.get_response_status() == tlm::TLM_INCOMPLETE_RESPONSE)
41	      trans.set_response_status(tlm::TLM_OK_RESPONSE);
42	    delay += sc_core::sc_time(cycles, sc_core::SC_NS);
43	  }
44	
45	private:
46	  auto handle_trans(tlm::tlm_generic_payload& trans) -> unsigned
47	  {
48	    const auto addr = trans.get_address();
49	    const auto len = trans.get_data_length();
50	    const auto ptr = trans.get_data_ptr();
51	    const auto byte_enable_len = trans.get_byte_enable_length();
52	    const auto byte_enable_ptr = trans.get_byte_enable_ptr();
53	
54	    spdlog::debug("mem: {}, addr={:#x}, len={}",
55	                  trans.is_read() ? "read" : "write", addr, len);
56	
57	    uint64_t offset;
58	    if (region.contains({addr, addr + len})) [[likely]] {
59	      offset = addr - this->region.base_address;
60	    } else if (alias_region.contains({addr, addr + len})) {
61	      offset = addr - this->alias_region.base_address;
62	    } else {
63	      spdlog::error(
64	        "transaction is out of bounds of memory region [{:#x}-{:#x}]",
65	        this->region.base_address, this->region.end_address);
66	      trans.set_response_status(tlm::TLM_ADDRESS_ERROR_RESPONSE);
67	      return latency;
68	    }
69	    const auto buf = std::span{ptr, ptr + len};
70	    if (trans.is_read()) [[likely]] {
71	      std::copy_n(this->data.begin() + offset, len, buf.begin());
72	      return latency;
73	    }
74	
75	    if (!trans.is_write()) [[unlikely]] {
76	      throw std::runtime_error("unimplemented");
77	    }
78	
79	    // write operation
80	    if (byte_enable_len == 0) [[likely]] {
81	      std::copy_n(buf.begin(), len, this->data.begin() + offset);
82	      return latency;
83	    }
84	
85	    // handle byte strobe if needed
86	    // AXI/AHB may split an un-aligned write into multiple aligned writes
87	    // with byte enable mask
88	    assert(byte_enable_len == len);
89	    for (unsigned i = 0; i < len; i++) {
90	      if (byte_enable_ptr[i] == 0xff)
91	        this->data[offset + i] = buf[i];
92	    }
93	    return latency;
94	  }
95	};
