16	template<typename CPU>
17	class ContextManager
18	{
19	public:
20	  bool save_on_wfi = false;
21	  bool continue_from = false;
22	  std::string dir = "./saved_ctx/";
23	
24	  template<typename PLATFORM>
25	  void restore(PLATFORM& platform, CPU& cpu) const
26	  {
27	    load_gz_memory(platform.main_memory.data, dir + "/main_memory");
28	#ifdef VSIMSAVABLE
29	    VerilatedRestore os;
30	    double time;
31	    os.open(dir + "/context");
32	    os >> time;
33	    os >> cpu;
34	    // TODO: how to restore simulation time?
35	#else
36	    (void) cpu;
37	    spdlog::critical(
38	      "Context restore not supported (VSIMSAVABLE not compiled)");
39	#endif
40	  }
41	
42	  template<typename PLATFORM>
43	  void save(PLATFORM& platform, CPU& cpu) const
44	  {
45	    dump_gz_memory(platform.main_memory.data, dir + "/main_memory");
46	#ifdef VSIMSAVABLE
47	    VerilatedSave os;
48	    os.open(dir + "/context");
49	    os << (double) sc_core::sc_time_stamp().value();
50	    os << cpu;
51	#else
52	    (void) cpu;
53	    spdlog::critical("Context save not supported (VSIMSAVABLE not compiled)");
54	#endif
55	  }
56	};
