22	struct ax45mpv_premium_cpu_cluster_subsystem
23	    : public Vax45mpv_premium,
24	      public CpuSignalRegistry<ax45mpv_premium_cpu_cluster_subsystem>
25	{
26	  using SC_CURRENT_USER_MODULE = ax45mpv_premium_cpu_cluster_subsystem;
27	
28	  ax45mpv_premium_cpu_cluster_subsystem(
29	    const sc_core::sc_module_name& name = "ax45mpv_premium")
30	      : Vax45mpv_premium{name}
31	  {}
32	
33	#define VERILOG_DEFINE(key, value) static constexpr auto key = value;
34	#include <Vax45mpv_premium_config.h>
35	
36	  // Limit maximum number of cores to 2 due to performance concerns
37	  static_assert(
