510	      mem[i] = word;
511	#endif
512	    }
513	
514	    spdlog::info("DLM loaded: {} x {}-bit words", word_count, word_size * 8);
515	  }
516	#undef SIZE
517	#endif // _NDS_DLM_SIZE_KB > 0
518	
519	  // Returns all committed PCs from all cores and all issue slots
520	  // Result: vector[core_id] contains vector of committed PCs for that core
521	  // Each inner vector has 0-2 entries depending on how many instructions
522	  // committed (ax45mpv is 2-issue)
523	  std::vector<std::vector<uint64_t>> get_committed_pc()
524	  {
525	    std::vector<std::vector<uint64_t>> result(_NDS_NHART);
526	
527	    // Core 0 - 2 issue slots
528	    if (this->rootp->WB_I0_RETIRE_C0) {
529	      result[0].push_back(this->rootp->WB_I0_PC_C0);
530	    }
531	    if (this->rootp->WB_I1_RETIRE_C0) {
532	      result[0].push_back(this->rootp->WB_I1_PC_C0);
533	    }
534	
535	#if _NDS_NHART > 1
536	    // Core 1 - 2 issue slots
537	    if (this->rootp->WB_I0_RETIRE_C1) {
538	      result[1].push_back(this->rootp->WB_I0_PC_C1);
539	    }
540	    if (this->rootp->WB_I1_RETIRE_C1) {
541	      result[1].push_back(this->rootp->WB_I1_PC_C1);
542	    }
543	#endif
544	
545	    return result;
546	  }
547	
548	  // Returns last PC values from all issue slots (no retire check)
549	  // Result: vector[core_id] contains all PC values from that core's issue slots
550	  // Always returns 2 entries per core (may contain stale values if slot didn't
551	  // commit)
552	  std::vector<std::vector<uint64_t>> get_last_committed_pc()
553	  {
554	#if _NDS_NHART > 1
555	    return {{this->rootp->WB_I0_PC_C0, this->rootp->WB_I1_PC_C0},
556	            { this->rootp->WB_I0_PC_C1,
557	              this->rootp->WB_I1_PC_C1 }};
558	#else
559	    return {{this->rootp->WB_I0_PC_C0, this->rootp->WB_I1_PC_C0}};
560	#endif
561	  }
