563	  static CpuSignalRegistry<ax45mpv_premium_cpu_cluster_subsystem>::Registry
564	  build_signal_registry()
565	  {
566	    using Self = ax45mpv_premium_cpu_cluster_subsystem;
567	    CpuSignalRegistry<Self>::Registry reg;
568	
569	#if defined(EXPAND_INTERNAL_SIGNALS)
570	#define X(name, signal) \
571	  reg.emplace(#name, [](const Self& s) -> uint64_t { \
572	    return widen_to_u64(s.rootp->signal); \
573	  });
574	    EXPAND_INTERNAL_SIGNALS
575	    EXPAND_VPU_INTERNAL_SIGNALS
576	#undef X
577	#endif // EXPAND_INTERNAL_SIGNALS
578	
579	#if defined(EXPAND_INTERNAL_MASKED_SIGNALS)
580	#define X(name, signal, shift, mask) \
581	  reg.emplace(#name, [](const Self& s) -> uint64_t { \
582	    return static_cast<uint64_t>((s.rootp->signal >> (shift)) & (mask)); \
583	  });
584	    EXPAND_INTERNAL_MASKED_SIGNALS
585	#undef X
586	#endif // EXPAND_INTERNAL_MASKED_SIGNALS
587	
588	    // decode[36] = write to mask register
589	    // decode[47] = reduction, write to single vd
590	    // decode[50] = vd whole register
591	    reg.emplace("i0_write_whole_vd", [](const Self& s) -> uint64_t {
592	      auto& d =
593	        s.rootp
594	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
595	          .m_storage;
596	      return ((d[1] >> 4) & 0x1) | ((d[1] >> 15) & 0x1) | ((d[1] >> 18) & 0x1);
597	    });
598	
599	    reg.emplace("i1_write_whole_vd", [](const Self& s) -> uint64_t {
600	      auto& d =
601	        s.rootp
602	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
603	          .m_storage;
604	      return ((d[1] >> 4) & 0x1) | ((d[1] >> 15) & 0x1) | ((d[1] >> 18) & 0x1);
605	    });
606	
607	    // decode[46:44] = vd whole register
608	    reg.emplace("i0_whole_vd_num", [](const Self& s) -> uint64_t {
609	      auto& d =
610	        s.rootp
611	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
612	          .m_storage;
613	      return ((d[1] >> 12) & 0b111) + 1;
614	    });
615	
616	    reg.emplace("i1_whole_vd_num", [](const Self& s) -> uint64_t {
617	      auto& d =
618	        s.rootp
619	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
620	          .m_storage;
621	      return ((d[1] >> 12) & 0b111) + 1;
622	    });
623	
624	    // decode[20] = rd1 write enable
625	    reg.emplace("i0_rd1_wen", [](const Self& s) -> uint64_t {
626	      auto& d =
627	        s.rootp
628	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
629	          .m_storage;
630	      return ((d[0] >> 20) & 0b1);
631	    });
632	
633	    reg.emplace("i1_rd1_wen", [](const Self& s) -> uint64_t {
634	      auto& d =
635	        s.rootp
636	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
637	          .m_storage;
638	      return ((d[0] >> 20) & 0b1);
639	    });
640	
641	    // decode[52] = vd_x2, widening instr
642	    reg.emplace("i0_vd_x2", [](const Self& s) -> uint64_t {
643	      auto& d =
644	        s.rootp
645	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
646	          .m_storage;
647	      return ((d[1] >> 20) & 0b1);
648	    });
649	
650	    reg.emplace("i1_vd_x2", [](const Self& s) -> uint64_t {
651	      auto& d =
652	        s.rootp
653	          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
654	          .m_storage;
655	      return ((d[1] >> 20) & 0b1);
656	    });
657	
658	    return reg;
659	  }
