102	extern "C" auto sc_main(const int argc, char* argv[]) -> int
103	try {
104	  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
105	  spdlog::set_pattern("[%^%l%$] %v");
106	
107	  const auto args = [&] {
108	    struct args
109	    {
110	      std::string pc_trace_file{};
111	      std::string elf_file{};
112	      std::optional<uint16_t> jtag_port = std::nullopt;
113	      bool memmap = false;
114	      std::string waveform_file{};
115	      unsigned mem_latency = 1;
116	      std::string ilm_file{};
117	      std::string dlm_file{};
118	      std::string kanata_file{};
119	      std::string objdump_file{};
120	      std::string clarity_file{};
121	      std::optional<uint64_t> kanata_loop_start{};
122	      std::optional<uint64_t> kanata_loop_end{};
123	      uint64_t kanata_loop_skip = 0;
124	      uint64_t kanata_loop_record = 1;
125	      std::vector<std::string> reset_vectors{};
126	      bool continue_ctx = false;
127	      bool save_ctx = false;
128	      std::string context_dir = "./saved_ctx/";
129	    } args;
130	
131	    const auto help_and_exit = [] {
132	      print_help();
133	      exit(0);
134	    };
135	
136	    auto p = parser{};
137	    p.shortflag('h', help_and_exit);
138	    p.longflag("help", help_and_exit);
139	    p.longflag("version", [] {
140	      print_version();
141	      exit(0);
142	    });
143	    p.longflag("print-memmap", [&] { args.memmap = true; });
144	    p.longflag("print-config", [] {
145	      print_cpu_configuration();
146	      exit(0);
147	    });
148	    p.longopt("jtag-port", [&](const std::string_view s) {
149	      if (auto n = to_int<uint16_t>(s); n)
150	        args.jtag_port = *n;
151	      else
152	        throw std::runtime_error("invalid number for --jtag-port: "
153	                                 + std::string{s});
154	    });
155	    p.longopt("mem-latency", [&](const std::string_view s) {
156	      if (auto n = to_int<unsigned>(s); n)
157	        args.mem_latency = *n;
158	      else
159	        throw std::runtime_error("invalid number for --mem-latency: "
160	                                 + std::string{s});
161	    });
162	    p.longopt("log-level", [](const std::string_view s) {
163	      if (auto n = to_int<uint16_t>(s); n) {
164	        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
165	        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
166	      } else {
167	        throw std::runtime_error("invalid number for --log-level: "
168	                                 + std::string{s});
169	      }
170	    });
171	    p.longopt("waveform",
172	              [&](const std::string_view s) { args.waveform_file = s; });
173	    p.longopt("ilm", [&](const std::string_view s) { args.ilm_file = s; });
174	    p.longopt("dlm", [&](const std::string_view s) { args.dlm_file = s; });
175	    p.longopt("pc-trace",
176	              [&](const std::string_view s) { args.pc_trace_file = s; });
177	    p.longopt("kanata",
178	              [&](const std::string_view s) { args.kanata_file = s; });
179	    p.longopt("objdump",
180	              [&](const std::string_view s) { args.objdump_file = s; });
181	    p.longopt("clarity",
182	              [&](const std::string_view s) { args.clarity_file = s; });
183	    p.longopt("kanata-loop-start", [&](const std::string_view s) {
184	      try {
185	        args.kanata_loop_start = std::stoull(std::string{s}, nullptr, 0);
186	      } catch (...) {
187	        throw std::runtime_error("invalid --kanata-loop-start: "
188	                                 + std::string{s});
189	      }
190	    });
191	    p.longopt("kanata-loop-end", [&](const std::string_view s) {
192	      try {
193	        args.kanata_loop_end = std::stoull(std::string{s}, nullptr, 0);
194	      } catch (...) {
195	        throw std::runtime_error("invalid --kanata-loop-end: "
196	                                 + std::string{s});
197	      }
198	    });
199	    p.longopt("kanata-loop-skip", [&](const std::string_view s) {
200	      try {
201	        args.kanata_loop_skip = std::stoull(std::string{s}, nullptr, 0);
202	      } catch (...) {
203	        throw std::runtime_error("invalid --kanata-loop-skip: "
204	                                 + std::string{s});
205	      }
206	    });
207	    p.longopt("kanata-loop-record", [&](const std::string_view s) {
208	      try {
209	        args.kanata_loop_record = std::stoull(std::string{s}, nullptr, 0);
210	      } catch (...) {
211	        throw std::runtime_error("invalid --kanata-loop-record: "
212	                                 + std::string{s});
213	      }
214	    });
215	    p.longflag("continue", [&] { args.continue_ctx = true; });
216	    p.longflag("save", [&] { args.save_ctx = true; });
217	    p.longopt("context-dir",
218	              [&](const std::string_view s) { args.context_dir = s; });
219	    p.longopt("reset-vector", [&](const std::string_view s) {
220	      args.reset_vectors.emplace_back(s);
221	    });
222	    p.posarg([&](const std::string_view s) { args.elf_file = s; });
223	    p.parse(std::vector<std::string_view>(argv, argv + argc));
224	    return args;
225	  }();
226	
227	#ifndef VSIMSAVABLE
228	  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
229	  {
230	    spdlog::critical(
231	      "--save, --continue, and --context-dir require VSIMSAVABLE build");
232	    std::exit(EXIT_FAILURE);
233	  }
234	#endif
235	
236	  print_version();
237	
238	  // systemc and cci init
239	  auto broker = cci_utils::broker{"global_broker"};
240	  cci::cci_register_broker(broker);
241	
242	  const auto time_resolution = sc_core::sc_get_time_resolution();
243	  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
244	
245	  // run simulation
246	  const auto do_sim = [&]<typename CPU>() -> int {
247	    Simulator<CPU> sim{"sim"};
248	
249	    if (args.memmap) {
250	      sim.platform.interconnect.dump_region();
251	      return 0;
252	    }
253	
254	    sim.set_mem_latency(args.mem_latency);
255	
256	    if (!args.ilm_file.empty())
257	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
258	
259	    if (!args.dlm_file.empty())
260	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
261	
262	    // End of elaboration
263	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
264	
265	    const auto t0 = std::chrono::steady_clock::now();
266	
267	    if (!args.waveform_file.empty())
268	      sim.enable_waveform(args.waveform_file);
269	
270	    if (!args.pc_trace_file.empty())
271	      sim.enable_pc_trace(args.pc_trace_file);
272	
273	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
274	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
275	
276	    std::optional<kanata::LoopGate> loop_gate;
277	    if (args.kanata_loop_start.has_value()
278	        != args.kanata_loop_end.has_value())
279	      throw std::runtime_error(
280	        "--kanata-loop-start and --kanata-loop-end must be specified together");
281	    if (args.kanata_loop_start.has_value()) {
282	      if (args.kanata_file.empty() && args.clarity_file.empty())
283	        throw std::runtime_error(
284	          "--kanata-loop-* requires --kanata or --clarity");
285	      if (args.kanata_loop_record == 0)
286	        throw std::runtime_error("--kanata-loop-record must be >= 1");
287	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
288	                                   *args.kanata_loop_end,
289	                                   args.kanata_loop_skip,
290	                                   args.kanata_loop_record};
291	    }
292	
293	    if (!args.kanata_file.empty())
294	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
295	
296	    if (!args.clarity_file.empty())
297	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
298	
299	    if (!args.elf_file.empty() && !args.continue_ctx)
300	      sim.load_elf(args.elf_file);
301	
302	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
303	    for (const auto& s: args.reset_vectors) {
304	      auto [hart, addr] = parse_reset_vector(s);
305	      if (hart) {
306	        sim.set_reset_vector(*hart, addr);
307	      } else {
308	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
309	          sim.set_reset_vector(i, addr);
310	      }
311	    }
312	
313	    if (args.continue_ctx)
314	      spdlog::info("You're resuming program from the given context");
315	
316	    if (args.jtag_port)
317	      sim.init_debug_port(args.jtag_port.value());
318	
319	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx)
320	      throw std::runtime_error("Required arg : program or --jtag-port");
321	
322	    if (args.continue_ctx || args.save_ctx) {
323	      std::string_view s = args.context_dir;
324	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
325	        throw std::runtime_error("Error: Path " + std::string{s}
326	                                 + " exists but is not a directory.");
327	      if (!std::filesystem::exists(s)) {
328	        try {
329	          std::filesystem::create_directories(s);
330	        } catch (const std::filesystem::filesystem_error& e) {
331	          throw std::runtime_error(std::string{"Failed to create directory: "}
332	                                   + e.what());
333	        }
334	      }
335	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
336	    }
337	
338	    sim.reset();
339	
340	    const int exit_code = sim.run();
341	
342	    sim.cpu.final();
343	
344	    const auto t1 = std::chrono::steady_clock::now();
345	    const auto cycles = sim.get_cycles();
346	    spdlog::info("{} cycles simulated", cycles);
347	    if (cycles > 0) {
348	      const auto ms =
349	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
350	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
351	                   ms.count() % 1000,
352	                   double(cycles) / double(ms.count()) * 1000.0);
353	    }
354	    return exit_code;
355	  };
356	
357	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
358	
359	} catch (const std::exception& e) {
360	  spdlog::critical("fatal exception: {}\n", e.what());
361	  std::exit(EXIT_FAILURE);
362	} catch (...) {
363	  std::terminate();
364	}
