99	inline void read_binary_file(const std::string& path, auto&& setter)
100	{
101	  std::ifstream file(path, std::ios::binary);
102	  if (!file)
103	    throw std::runtime_error("Failed to open file: " + path);
104	
105	  std::vector<uint8_t> data((std::istreambuf_iterator<char>(file)),
106	                            std::istreambuf_iterator<char>());
107	  setter(data);
108	  spdlog::info("Loaded {} bytes from {}", data.size(), path);
109	}
